             for (c.args) |arg| {
                 if (checkExprForBigIntMethodCall(arg, method_name, param_index)) return true;
             }
+            // Check keyword arguments
+            for (c.keyword_args) |kw| {
+                if (checkExprForBigIntMethodCall(kw.value, method_name, param_index)) return true;
